/// CP949 (EUC-KR superset) 바이트를 유니코드 문자열로 디코딩하는 모듈.
///
/// AutoCAD DXF 파일에서 ANSI_949 코드페이지로 인코딩된 한글 텍스트를
/// 올바르게 읽기 위해 사용합니다.
///
/// 매핑 테이블은 lead byte별 String으로 저장하여 컴파일러 부하를 최소화합니다.

/// CP949 바이트 시퀀스를 유니코드 문자열로 디코딩합니다.
String decodeCP949(List<int> bytes) {
  final sb = StringBuffer();
  int i = 0;
  while (i < bytes.length) {
    final b = bytes[i];
    if (b <= 0x7F) {
      sb.writeCharCode(b);
      i++;
    } else if (i + 1 < bytes.length) {
      final lead = b;
      final trail = bytes[i + 1];
      if (lead >= 0x81 && lead <= 0xFE) {
        final tableIndex = lead - 0x81;
        final trailIndex = trail < 0x80 ? trail - 0x41 : trail - 0x80 + 62;
        if (tableIndex < _tables.length && trailIndex >= 0 && trailIndex < 189) {
          final table = _tables[tableIndex];
          if (table != null && trailIndex < table.length) {
            final cp = table.codeUnitAt(trailIndex);
            if (cp != 0) {
              sb.writeCharCode(cp);
              i += 2;
              continue;
            }
          }
        }
      }
      sb.writeCharCode(0xFFFD);
      i += 2;
    } else {
      sb.writeCharCode(0xFFFD);
      i++;
    }
  }
  return sb.toString();
}

/// 유니코드 문자열을 CP949 바이트로 인코딩합니다.
List<int> encodeCP949(String text) {
  _ensureReverse();
  final result = <int>[];
  for (final codeUnit in text.codeUnits) {
    if (codeUnit <= 0x7F) {
      result.add(codeUnit);
    } else {
      final cp949 = _unicodeToCP949[codeUnit];
      if (cp949 != null) {
        result.add(cp949 >> 8);
        result.add(cp949 & 0xFF);
      } else {
        result.add(0x3F); // '?'
      }
    }
  }
  return result;
}

Map<int, int>? _reverseMap;
void _ensureReverse() {
  if (_reverseMap != null) return;
  _reverseMap = <int, int>{};
  for (int lead = 0x81; lead <= 0xFE; lead++) {
    final tableIndex = lead - 0x81;
    if (tableIndex >= _tables.length) break;
    final table = _tables[tableIndex];
    if (table == null) continue;
    for (int ti = 0; ti < table.length; ti++) {
      final cp = table.codeUnitAt(ti);
      if (cp != 0) {
        final trail = ti < 62 ? ti + 0x41 : ti - 62 + 0x80;
        _reverseMap![cp] = (lead << 8) | trail;
      }
    }
  }
}
Map<int, int> get _unicodeToCP949 {
  _ensureReverse();
  return _reverseMap!;
}

